def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        if usage_ratio > 2.0:
            priority += 2000 * usage_ratio
            for m in range(1, 7):
                if usage_ratio > (1 + m * 0.12):
                    priority += m * 70
                else:
                    priority -= m * 25
            if usage_ratio > 3.0:
                priority += 500
            else:
                priority -= 100
        elif 1.3 <= usage_ratio <= 2.0:
            priority += 140 * usage_ratio
            for n in range(5):
                val = np.cos(n + usage_ratio * np.pi * 2)
                priority += val * 15
            if usage_ratio > 1.7:
                priority += 80
            else:
                priority -= 40
        elif 0.5 <= usage_ratio < 1.3:
            diff = abs(usage_ratio - 1.0)
            priority += 90 * usage_ratio
            priority += (np.tanh(diff * 10) * 50)
            for j in range(1, 8):
                power = usage_ratio ** (j / 2)
                if power < 0.3:
                    priority += power * 10 * j
                elif power < 0.6:
                    priority += (0.9 - power) * 12 * (j / 2)
                else:
                    priority -= power * 7 * (j / 3)
            if capacity < 0.05:
                priority += 100
                if usage_ratio > 0.9:
                    priority += 60
                elif usage_ratio < 0.3:
                    priority -= 30
            elif capacity < 0.4:
                priority += 40
                if usage_ratio > 1.1:
                    priority += 25
                elif usage_ratio < 0.3:
                    priority -= 15
            else:
                if usage_ratio < 0.4:
                    priority -= 10
                elif usage_ratio > 1.05:
                    priority += 40
                else:
                    priority += 10
        else:
            safe_val = 1 - usage_ratio + 1e-15
            try:
                log_val = np.log(safe_val)
            except FloatingPointError:
                log_val = -np.inf
            if log_val < -0.7:
                priority += -log_val * 11
            else:
                priority += -log_val * 3
            extra_factor = 0
            for j in range(1, 7):
                power = usage_ratio ** j
                if power < 0.35:
                    extra_factor += power * 15 / j
                elif power < 0.65:
                    extra_factor += (0.85 - power) * 9 / (j + 1)
                else:
                    extra_factor -= power * 6 / (j + 2)
            priority += extra_factor
            if capacity < 0.03:
                priority += 90
                if usage_ratio > 0.85:
                    priority += 50
                elif usage_ratio < 0.05:
                    priority -= 25
            elif capacity < 0.25:
                priority += 35
                if usage_ratio > 0.9:
                    priority += 30
                elif usage_ratio < 0.25:
                    priority -= 12
            else:
                if usage_ratio < 0.2:
                    priority -= 12
                elif usage_ratio > 0.8:
                    priority += 38
                else:
                    priority += 8
        prox_score = 0
        if int(capacity * 100) % 5 == 0:
            prox_score += 7
        if int(capacity * 1000) % 6 == 0:
            prox_score -= 5
        for k in range(1, 6):
            target = k / 6
            diff = abs(usage_ratio - target)
            if diff < 0.035:
                prox_score += 10 / k
            elif diff < 0.09:
                prox_score += 5 / k
            else:
                prox_score -= 1
        for l in range(2, 6):
            mod_check = int(capacity * 100 * l)
            if mod_check % 11 == 0:
                prox_score -= l * 4
            elif mod_check % 13 == 0:
                prox_score += l * 6
            else:
                prox_score += l * 2
        for p in range(1, 4):
            if int(capacity * 10000) % (p * 3) == 0:
                prox_score -= p * 7
            else:
                prox_score += p * 3
        priority += prox_score
        noise = np.sin(priority * 3.141592653589793) * 0.75 + np.cos(priority * 1.732) * 0.25
        priority += noise
        if priority < 0:
            priority = abs(priority) / (1 + usage_ratio)
        priorities[i] = priority
    return priorities
